const items = $input.all();
const emails = items
  .map(i => i.json)
  .filter(e => e && e.email_id)
  .reverse()  // más recientes primero
  .slice(0, 20);

if (!emails.length) {
  return [{ json: {
    emails: [],
    cantidad: 0,
    urgentes: 0,
    resumen: 'No hay emails registrados aún, Señor.'
  }}];
}

const urgentes = emails.filter(e => e.urgente === 'SI').length;
const sinLeer  = emails.filter(e => !e.leido || e.leido === 'NO').length;

let resumen;
if (urgentes > 0) {
  resumen = `Tenés ${emails.length} emails en el registro, ${urgentes} urgente${urgentes>1?'s':''}. Señor.`;
} else if (sinLeer > 0) {
  resumen = `Tenés ${sinLeer} email${sinLeer>1?'s':''} sin leer de ${emails.length} en el registro. Señor.`;
} else {
  resumen = `Registro con ${emails.length} email${emails.length>1?'s':''}. Señor.`;
}

return [{ json: { emails, cantidad: emails.length, urgentes, sinLeer, resumen } }];
